    if (inputRows.length && !distillation) gaps.push({ reason: "存在 provider ranking memory usage receipt repair 行但未触发 typed memory 蒸馏" });
    if (inputRows.length && Number(archive.archived_count || 0) < 1) gaps.push({ reason: "provider ranking memory usage receipt repair archive 为空" });
    if (inputRows.length && !disciplineDocs.length) gaps.push({ reason: "未写入 provider ranking memory usage receipt discipline typed MEMORY.md 文档" });
    if (disciplineDocs.length && !/provider-ranking-provenance-compact-repair-receipt-memory\.md/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 provider ranking compact repair receipt memory doc relPath" });
    if (disciplineDocs.length && !/memoryUsed/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 memoryUsed 规则" });
    if (disciplineDocs.length && !/memoryIgnored/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 memoryIgnored 规则" });
    if (disciplineDocs.length && !/usageState|usage_state/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 usageState 规则" });
    if (disciplineDocs.length && !/ranking evidence only, not authorization/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 ranking evidence only, not authorization 边界" });
    if (disciplineDocs.length && !/fresh valid provider switch decision receipt/i.test(docText)) gaps.push({ reason: "typed memory 文档缺少 fresh valid provider switch decision receipt 要求" });
    if (inputRows.length && !/provider-ranking-memory-usage-receipt-discipline\.md|memoryUsed|memoryIgnored|usageState|fresh valid provider switch decision receipt|ranking evidence only, not authorization/i.test(recallText)) {
      gaps.push({ reason: "provider ranking memory usage receipt discipline typed memory 无法通过 recall probe 召回" });
    }
